),
inserted AS (
  INSERT INTO adressen (id, plz, ort, strasse, hausnummer, zusatz, lat, lon, titel, arzt_name, geo_name, import_batch)
  SELECT uuid_generate_v4(), i.plz, i.ort, i.strasse, i.hausnummer, i.zusatz, i.lat, i.lon, i.titel, i.arzt_name, i.geo_name, i.import_batch
  FROM incoming i
  WHERE NOT EXISTS (
    SELECT 1 FROM adressen a
    WHERE lower(trim(coalesce(a.arzt_name, ''))) = lower(trim(coalesce(i.arzt_name, '')))
      AND lower(regexp_replace(trim(coalesce(a.strasse, '')), '\s+', ' ', 'g')) = lower(regexp_replace(trim(coalesce(i.strasse, '')), '\s+', ' ', 'g'))
  )
  RETURNING id
)
SELECT (SELECT COUNT(*) FROM incoming) AS incoming_rows, (SELECT COUNT(*) FROM inserted) AS inserted_rows;
COMMIT;
